urlset:
{%- set base_url = SITEURL if SITEURL else "https://flisolcuenca.github.io" %}

{# Página principal #}

  {{ base_url }}/
  {{ EVENT_DATE_START[:10] }}
  weekly
  1.0



{# Secciones como anclas — ayudan a crawlers que siguen fragment links #}
{%- set sections = [
  ('hero',          '1.0', 'weekly'),
  ('inscripciones', '0.9', 'weekly'),
  ('agenda',        '0.9', 'weekly'),
  ('comunidades',   '0.8', 'monthly'),
  ('installfest',   '0.8', 'monthly'),
  ('sponsors',      '0.7', 'monthly'),
  ('contacto',      '0.7', 'monthly'),
] %}
{%- for anchor, priority, freq in sections %}

  {{ base_url }}/#{{ anchor }}
  {{ EVENT_DATE_START[:10] }}
  {{ freq }}
  {{ priority }}


{%- endfor %}
